{"code": "import json

# Get Europe metadata with article IDs and publication dates
europe_metadata = locals()['var_functions.query_db:10']

if isinstance(europe_metadata, str) and europe_metadata.endswith('.json'):
    with open(europe_metadata, 'r') as f:
        europe_metadata = json.load(f)

# Group articles by year to process incrementally
from collections import defaultdict
articles_by_year = defaultdict(list)
for item in europe_metadata:
    year = int(item['publication_date'][:4])
    articles_by_year[year].append(int(item['article_id']))

print('__RESULT__:')
print(json.dumps({
    'total_articles': len(europe_metadata),
    'year_range': f'{min(articles_by_year.keys())}-{max(articles_by_year.keys())}',
    'articles_per_year': {year: len(ids) for year, ids in sorted(articles_by_year.items())}
}))"}

